'use strict'

var express = require('../../..');

var apiv1 = express.Router();

apiv1.get('/', function(req, res) {
  res.send('Hello from APIv1 root route.');
});

apiv1.get('/users', function(req, res) {
  res.send('List of APIv1 users.');
});

module.exports = apiv1;

res.links = function(links) {
  var link = this.get('Link') || '';
  if (link) link += ', ';
  return this.set('Link', link + Object.keys(links).map(function(rel) {
    // Allow multiple links if links[rel] is an array
    if (Array.isArray(links[rel])) {
      return links[rel].map(function (singleLink) {
        return `<${singleLink}>; rel="${rel}"`;
      }).join(', ');
    } else {
      return `<${links[rel]}>; rel="${rel}"`;
    }
  }).join(', '));
};

async (req, res, next) => {
  if (!req.oidc.isAuthenticated()) {
    next();
    return;
  }
  try {
    const loggedOut = await isLoggedOutFn(req, config);
    if (loggedOut) {
      req[config.session.name] = undefined;
    }
    next();
  } catch (e) {
    next(e);
  }
}

function wrap(fn) {
  const newFn = function newFn(...args) {
    const ret = fn.apply(this, args);
    const next = (args.length === 5 ? args[2] : last(args)) || noop;
    if (ret && ret.catch) ret.catch(err => next(err));
    return ret;
  };
  Object.defineProperty(newFn, 'length', {
    value: fn.length,
    writable: false,
  });
  return copyFnProps(fn, newFn);
}

function getProtohost (url) {
  if (typeof url !== 'string' || url.length === 0 || url[0] === '/') {
    return undefined
  }

  const searchIndex = url.indexOf('?')
  const pathLength = searchIndex !== -1
    ? searchIndex
    : url.length
  const fqdnIndex = url.substring(0, pathLength).indexOf('://')

  return fqdnIndex !== -1
    ? url.substring(0, url.indexOf('/', 3 + fqdnIndex))
    : undefined
}

function next (err) {
  if (++i >= self._index.length) {
    if (err) return self.onStatError(err)
    return self.error(404)
  }

  var p = join(path, self._index[i])

  debug('stat "%s"', p)
  fs.stat(p, function (err, stat) {
    if (err) return next(err)
    if (stat.isDirectory()) return next()
    self.emit('file', p, stat)
    self.send(p, stat)
  })
}

function swaggerInitFn(req, res, next) {
  if (trimQuery(req.url).endsWith('/package.json')) {
    res.sendStatus(404)
  } else if (trimQuery(req.url).endsWith('/swagger-ui-init.js')) {
    res.set('Content-Type', 'application/javascript')
    res.send(swaggerInit)
  } else {
    next()
  }
}

function getProtohost(url) {
  if (url.length === 0 || url[0] === '/') {
    return undefined;
  }

  var fqdnIndex = url.indexOf('://')

  return fqdnIndex !== -1 && url.lastIndexOf('?', fqdnIndex) === -1
    ? url.substr(0, url.indexOf('/', 3 + fqdnIndex))
    : undefined;
}

function attachSessionObject(req, sessionName, value) {
  Object.defineProperty(req, sessionName, {
    enumerable: true,
    get() {
      return value;
    },
    set(arg) {
      if (arg === null || arg === undefined || arg[REASSIGN]) {
        value = arg;
      } else {
        throw new TypeError('session object cannot be reassigned');
      }
      return undefined;
    },
  });
}

function configureMaxAge(options) {
  var maxAge = (typeof options.maxAge === 'number' || options.maxAge) && options.maxAge.toString()
  if (maxAge && maxAge.length) {
    return {
      key: 'Access-Control-Max-Age',
      value: maxAge
    };
  }
  return null;
}

function clfdate (dateTime) {
  var date = dateTime.getUTCDate()
  var hour = dateTime.getUTCHours()
  var mins = dateTime.getUTCMinutes()
  var secs = dateTime.getUTCSeconds()
  var year = dateTime.getUTCFullYear()

  var month = CLF_MONTH[dateTime.getUTCMonth()]

  return pad2(date) + '/' + month + '/' + year +
    ':' + pad2(hour) + ':' + pad2(mins) + ':' + pad2(secs) +
    ' +0000'
}

constructor(tokenSet) {
  this.id_token = tokenSet.id_token;
  this.access_token = tokenSet.access_token;
  this.refresh_token = tokenSet.refresh_token;
  this.token_type = tokenSet.token_type;

  if (tokenSet.expires_at !== undefined) {
    this.expires_at = tokenSet.expires_at;
  } else if (tokenSet.expires_in !== undefined) {
    this.expires_at = Math.floor(Date.now() / 1000) + tokenSet.expires_in;
  }
}

public equivalents(): ContentType[] {
  const types: ContentType[] = [];
  if (!this.mediaType) {
    return types;
  }
  types.push(new ContentType(this.mediaType));

  if (!this.parameters['charset']) {
    types.push(new ContentType(`${this.normalize(['charset'])}; charset=utf-8`));
  }
  return types;
}

export const bindAll = <T>(object: T): { [K in keyof T]: T[K] } => {
  const protoKeys = Object.getOwnPropertyNames(Object.getPrototypeOf(object)) as (keyof T)[];
  protoKeys.forEach(key => {
    const maybeFn = object[key];
    if (typeof maybeFn === 'function' && key !== 'constructor') {
      object[key] = maybeFn.bind(object);
    }
  });

  return object;
};

function getStringLiteralValue(node: SgNode<Js>): string | null {
  if (!node.is('string')) return null

  const fragments = node.findAll({ rule: { kind: 'string_fragment' } })
  if (fragments.length !== 1) return null
  return fragments[0]?.text() ?? null
}
